"""Flask REST API wrapping TaskQueue."""

import pickle
from flask import Flask, jsonify, request
from src.task_queue import TaskQueue


def create_app():
    app = Flask(__name__)
    queue = TaskQueue()
    app.queue = queue  # expose for testing

    @app.post("/tasks")
    def submit_task():
        data = request.get_json(silent=True) or {}
        # Accept a serialized callable or a simple echo value
        if "task_fn" in data:
            try:
                task_fn = pickle.loads(bytes.fromhex(data["task_fn"]))
            except Exception:
                return jsonify({"error": "invalid task_fn"}), 400
        elif "value" in data:
            val = data["value"]
            task_fn = lambda: val  # noqa: E731
        else:
            return jsonify({"error": "provide task_fn or value"}), 400

        priority = data.get("priority", 0)
        task_id = queue.submit(task_fn, priority=priority)
        return jsonify({"task_id": task_id}), 201

    @app.get("/tasks/<task_id>")
    def get_task(task_id):
        status = queue.get_status(task_id)
        if status is None:
            return jsonify({"error": "not found"}), 404
        return jsonify({"task_id": task_id, **status})

    @app.get("/tasks")
    def list_tasks():
        with queue._lock:
            tasks = [
                {"task_id": tid, **dict(info)}
                for tid, info in queue._tasks.items()
            ]
        return jsonify(tasks)

    return app

"""Unit tests for TaskQueue."""

import time
import threading
import pytest
from src.task_queue import TaskQueue


@pytest.fixture
def q():
    return TaskQueue()


def wait_done(queue, task_id, timeout=2):
    """Poll until task reaches a terminal state."""
    deadline = time.time() + timeout
    while time.time() < deadline:
        s = queue.get_status(task_id)
        if s["status"] in ("done", "error"):
            return s
        time.sleep(0.01)
    return queue.get_status(task_id)


# --- submit / get_status basics ---

def test_submit_returns_task_id(q):
    tid = q.submit(lambda: 42)
    assert isinstance(tid, str) and len(tid) > 0


def test_status_initially_pending_or_running(q):
    tid = q.submit(lambda: time.sleep(0))
    status = q.get_status(tid)
    assert status["status"] in ("pending", "running", "done")


def test_task_executes_and_result_available(q):
    tid = q.submit(lambda: 99)
    s = wait_done(q, tid)
    assert s["status"] == "done"
    assert s["result"] == 99


def test_task_with_string_result(q):
    tid = q.submit(lambda: "hello")
    s = wait_done(q, tid)
    assert s["result"] == "hello"


def test_task_exception_captured(q):
    def boom():
        raise ValueError("oops")

    tid = q.submit(boom)
    s = wait_done(q, tid)
    assert s["status"] == "error"
    assert "oops" in s["error"]
    assert s["result"] is None


def test_get_status_unknown_id_raises(q):
    with pytest.raises(KeyError):
        q.get_status("nonexistent")


def test_submit_non_callable_raises(q):
    with pytest.raises(TypeError):
        q.submit("not_a_function")


def test_submit_non_integer_priority_raises(q):
    with pytest.raises(TypeError):
        q.submit(lambda: 1, priority=1.5)


# --- priority ordering ---

def test_higher_priority_runs_before_lower(q):
    """Submit tasks while worker is busy, verify execution order."""
    order = []
    barrier = threading.Event()

    # Block the worker so queued tasks pile up
    q.submit(lambda: barrier.wait(timeout=2))

    # Now enqueue tasks with different priorities
    q.submit(lambda: order.append("low"), priority=1)
    q.submit(lambda: order.append("high"), priority=10)
    q.submit(lambda: order.append("medium"), priority=5)

    barrier.set()

    # Wait for all three to finish
    deadline = time.time() + 3
    while time.time() < deadline and len(order) < 3:
        time.sleep(0.02)

    assert order == ["high", "medium", "low"], f"Got order: {order}"


def test_default_priority_zero(q):
    tid = q.submit(lambda: "ok")
    s = wait_done(q, tid)
    assert s["status"] == "done"


# --- thread safety ---

def test_concurrent_submits(q):
    results = []
    lock = threading.Lock()

    def submit_one():
        tid = q.submit(lambda: 1)
        with lock:
            results.append(tid)

    threads = [threading.Thread(target=submit_one) for _ in range(20)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    assert len(results) == 20
    assert len(set(results)) == 20  # all unique IDs


def test_concurrent_get_status(q):
    tids = [q.submit(lambda: 1) for _ in range(5)]

    errors = []

    def read_status():
        for tid in tids:
            try:
                q.get_status(tid)
            except Exception as e:
                errors.append(e)

    threads = [threading.Thread(target=read_status) for _ in range(10)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    assert not errors


# --- list_tasks ---

def test_list_tasks_returns_all(q):
    tids = {q.submit(lambda: i) for i in range(3)}
    listed = {t["task_id"] for t in q.list_tasks()}
    assert tids.issubset(listed)

