"""In-memory task queue with priority-based execution and thread safety."""

import threading
import uuid
from queue import PriorityQueue


class TaskQueue:
    def __init__(self):
        self._tasks = {}  # task_id -> {status, result, error}
        self._lock = threading.Lock()
        self._queue = PriorityQueue()
        self._worker = threading.Thread(target=self._run, daemon=True)
        self._worker.start()

    def submit(self, task_fn, priority=0):
        task_id = str(uuid.uuid4())
        with self._lock:
            self._tasks[task_id] = {"status": "pending", "result": None, "error": None}
        # Negate priority so higher values are processed first (PriorityQueue is min-heap)
        self._queue.put((-priority, task_id, task_fn))
        return task_id

    def get_status(self, task_id):
        with self._lock:
            task = self._tasks.get(task_id)
            if task is None:
                return None
            return dict(task)

    def _run(self):
        while True:
            _, task_id, task_fn = self._queue.get()
            with self._lock:
                self._tasks[task_id]["status"] = "running"
            try:
                result = task_fn()
                with self._lock:
                    self._tasks[task_id]["status"] = "done"
                    self._tasks[task_id]["result"] = result
            except Exception as e:
                with self._lock:
                    self._tasks[task_id]["status"] = "error"
                    self._tasks[task_id]["error"] = str(e)
            finally:
                self._queue.task_done()

"""Flask REST API for the TaskQueue."""

from flask import Flask, jsonify, request

from .task_queue import TaskQueue


def create_app():
    app = Flask(__name__)
    queue = TaskQueue()

    # Store serializable task representations alongside the queue
    _task_registry = {}  # task_id -> {"label": ...}

    @app.post("/tasks")
    def submit_task():
        body = request.get_json(silent=True) or {}
        label = body.get("label", "task")
        # The submitted "task" is a simple echo function returning the label
        task_fn = lambda: label  # noqa: E731
        task_id = queue.submit(task_fn, priority=body.get("priority", 0))
        _task_registry[task_id] = {"label": label}
        return jsonify({"task_id": task_id}), 201

    @app.get("/tasks/<task_id>")
    def get_task(task_id):
        status = queue.get_status(task_id)
        if status is None:
            return jsonify({"error": "not found"}), 404
        return jsonify({"task_id": task_id, **status})

    @app.get("/tasks")
    def list_tasks():
        result = []
        for task_id in list(_task_registry):
            status = queue.get_status(task_id)
            if status is not None:
                result.append({"task_id": task_id, **status})
        return jsonify(result)

    return app

"""Flask REST API for TaskQueue."""

import sys
import os

# Allow running from repo root or from src/
sys.path.insert(0, os.path.dirname(__file__))

from flask import Flask, jsonify, request
from task_queue import TaskQueue


def create_app(task_queue: TaskQueue | None = None) -> Flask:
    """Create and return the Flask application.

    :param task_queue: Optional :class:`TaskQueue` instance to use.  A new
        one is created when *None* (the default).  Pass an explicit instance
        in tests to keep control over the queue.
    """
    app = Flask(__name__)
    app.config["TESTING"] = False

    if task_queue is None:
        task_queue = TaskQueue()

    # Store on app so tests can reach it if needed
    app.task_queue = task_queue  # type: ignore[attr-defined]

    # ------------------------------------------------------------------
    # Routes
    # ------------------------------------------------------------------

    @app.post("/tasks")
    def submit_task():
        """POST /tasks — submit a new task.

        Expected JSON body::

            {"expression": "<python expression string>"}

        The expression is evaluated and its value becomes the task result.
        This is intentionally kept simple for demo purposes; real-world usage
        would accept a serialisable task description.
        """
        body = request.get_json(silent=True)
        if not body or "expression" not in body:
            return jsonify({"error": "Request body must be JSON with an 'expression' field"}), 400

        expression = body["expression"]
        if not isinstance(expression, str) or not expression.strip():
            return jsonify({"error": "'expression' must be a non-empty string"}), 400

        priority = body.get("priority", 0)
        if not isinstance(priority, int):
            return jsonify({"error": "'priority' must be an integer"}), 400

        # Build a callable that evaluates the expression
        expr_copy = expression  # closure capture

        def task_fn():
            return eval(expr_copy)  # noqa: S307 — demo-only evaluation

        try:
            task_id = task_queue.submit(task_fn, priority=priority)
        except TypeError as exc:
            return jsonify({"error": str(exc)}), 400

        return jsonify({"task_id": task_id}), 201

    @app.get("/tasks/<task_id>")
    def get_task(task_id: str):
        """GET /tasks/{id} — retrieve task status and result."""
        try:
            status = task_queue.get_status(task_id)
        except KeyError:
            return jsonify({"error": f"Task {task_id!r} not found"}), 404
        return jsonify({"task_id": task_id, **status}), 200

    @app.get("/tasks")
    def list_tasks():
        """GET /tasks — list all tasks."""
        return jsonify(task_queue.list_tasks()), 200

    # ------------------------------------------------------------------
    # Error handlers
    # ------------------------------------------------------------------

    @app.errorhandler(404)
    def not_found(exc):
        return jsonify({"error": "Not found"}), 404

    @app.errorhandler(405)
    def method_not_allowed(exc):
        return jsonify({"error": "Method not allowed"}), 405

    return app


if __name__ == "__main__":
    create_app().run(debug=True)
